import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button, Input, StatusBadge, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useYcmhPermissions } from '../../../hooks/useYcmhPermissions';
import { purchasingService } from '../../../services/mh/purchasingService';
import type { PurchaseRequestDto } from '../../../services/mh/models';
import { ycmhPageLabels } from '../../../constants/ycmhPageLabels';
import { formatDate, formatNumber } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import styles from '../../../styles/erpPage.module.css';
import df from '../../../styles/documentForm.module.css';

const YcmhDetailPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canWrite, canApprove } = useYcmhPermissions();
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const [data, setData] = useState<PurchaseRequestDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [rejectReason, setRejectReason] = useState('');
  const [showReject, setShowReject] = useState(false);
  const [acting, setActing] = useState(false);

  const reload = React.useCallback(() => {
    if (!id) return;
    let c = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getRequest(id)
        .then(r => { if (!c) setData(r); })
        .catch(err => dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, ycmhPageLabels.loadError),
          type: 'error',
        }))
        .finally(() => { if (!c) setLoading(false); });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [id, dispatch]);

  React.useEffect(() => {
    const cleanup = reload();
    return () => cleanup?.();
  }, [reload]);

  const handleApprove = async () => {
    if (!id) return;
    setActing(true);
    try {
      await purchasingService.approveRequest(id);
      dispatchAppToast(dispatch, { message: ycmhPageLabels.approveSuccess, type: 'success' });
      reload();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, ycmhPageLabels.approveError),
        type: 'error',
      });
    } finally { setActing(false); }
  };

  const handleReject = async () => {
    if (!id || !rejectReason.trim()) {
      dispatchAppToast(dispatch, { message: ycmhPageLabels.rejectReasonRequired, type: 'warning' });
      return;
    }
    setActing(true);
    try {
      await purchasingService.rejectRequest(id, rejectReason);
      dispatchAppToast(dispatch, { message: ycmhPageLabels.rejectSuccess, type: 'success' });
      setShowReject(false);
      reload();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, ycmhPageLabels.rejectError),
        type: 'error',
      });
    } finally { setActing(false); }
  };

  if (loading || !data) {
    return (
      <div className={styles.page} data-testid="erp-mh-ycmh-detail-loading">
        <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
      </div>
    );
  }

  return (
    <div className={styles.page} data-testid="erp-mh-ycmh-detail">
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-file-invoice" /> YCMH {data.code}</h1>
          <p className={styles.subtitle}>{formatDate(data.requestDate)} · {data.departmentName ?? '—'}</p>
        </div>
        <div className={styles.headerActions}>
          <Button variant="secondary" onClick={() => navigate('/mh/ycmh')}>Danh sách</Button>
          {data.status === 'Draft' && canWrite && (
            <Button variant="secondary" onClick={() => navigate(`/mh/ycmh/them?editId=${data.id}`)}>Sửa</Button>
          )}
          {data.status === 'PendingApproval' && canApprove && (
            <>
              <Button variant="primary" onClick={handleApprove} disabled={acting}>Duyệt</Button>
              <Button variant="secondary" onClick={() => setShowReject(v => !v)}>Từ chối</Button>
            </>
          )}
        </div>
      </div>
      <div className={styles.summaryBar}>
        <div className={styles.summaryItem}><label className={df.label}>Trạng thái</label><StatusBadge status={data.status} /></div>
        <div className={styles.summaryItem}><label className={df.label}>Mô tả</label><strong>{data.description ?? '—'}</strong></div>
        {data.rejectReason && <div className={styles.summaryItem}><label className={df.label}>Lý do từ chối</label><strong>{data.rejectReason}</strong></div>}
      </div>
      {showReject && (
        <div className={df.section}>
          <div className={df.field}><label className={df.label}>Lý do từ chối</label><textarea value={rejectReason} onChange={e => setRejectReason(e.target.value)} /></div>
          <div className={styles.footer}><Button variant="primary" onClick={handleReject} disabled={acting}>Xác nhận từ chối</Button></div>
        </div>
      )}
      <div className={styles.tableCard}>
        <div className={styles.tableWrapper}>
          <table className={styles.table}>
            <thead><tr><th>Mã VT</th><th>ĐVT</th><th className={styles.colRight}>SL</th><th className={styles.colRight}>Giá DK</th><th>Ghi chú</th></tr></thead>
            <tbody>
              {data.lines.map((l, i) => (
                <tr key={l.id ?? i}><td><code>{l.materialCode}</code></td><td>{l.unitCode}</td>
                  <td className={styles.colRight}>{formatNumber(l.quantity)}</td>
                  <td className={styles.colRight}>{formatNumber(l.estimatedPrice)}</td><td>{l.note ?? '—'}</td></tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};
export default YcmhDetailPage;
